import React, { useState, useEffect, useRef } from 'react';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const formatDate = (iso) => new Date(iso).toLocaleDateString('fr-FR', {
  day: 'numeric', month: 'short', year: 'numeric'
});

// ══════════════════════════════════════════════════════════════
//  LOGIN FORM
// ══════════════════════════════════════════════════════════════
function LoginForm({ onLogin }) {
  const [form, setForm] = useState({ username: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res = await fetch(`${API_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form)
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      localStorage.setItem('bbrs_token', data.token);
      onLogin(data.token, data.user);
    } catch (err) {
      setError(err.message || 'Erreur de connexion');
    } finally {
      setLoading(false);
    }
  };

  const s = {
    page: {
      minHeight: '100vh',
      background: '#0a0f0a',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: "'Segoe UI', sans-serif",
      padding: '20px',
    },
    box: {
      background: 'rgba(255,255,255,0.03)',
      border: '1px solid rgba(0,200,0,0.2)',
      borderRadius: '20px',
      padding: '50px 40px',
      width: '100%',
      maxWidth: '420px',
      textAlign: 'center',
    },
    logo: { fontSize: '2.5rem', marginBottom: '8px' },
    title: { color: '#ffd700', fontSize: '1.6rem', fontWeight: 800, margin: '0 0 4px' },
    sub: { color: '#00aa00', fontSize: '0.9rem', marginBottom: '36px' },
    label: { display: 'block', color: '#888', fontSize: '0.8rem', textAlign: 'left', marginBottom: '6px', fontWeight: 600, letterSpacing: '0.5px' },
    input: {
      width: '100%',
      background: 'rgba(255,255,255,0.05)',
      border: '1px solid rgba(0,200,0,0.25)',
      borderRadius: '10px',
      padding: '12px 16px',
      color: '#e8e8e8',
      fontSize: '1rem',
      outline: 'none',
      marginBottom: '20px',
      boxSizing: 'border-box',
    },
    btn: {
      width: '100%',
      background: loading ? '#555' : 'linear-gradient(135deg, #00cc00, #007700)',
      color: '#fff',
      border: 'none',
      borderRadius: '10px',
      padding: '14px',
      fontSize: '1rem',
      fontWeight: 700,
      cursor: loading ? 'not-allowed' : 'pointer',
    },
    error: {
      background: 'rgba(255,60,60,0.1)',
      border: '1px solid rgba(255,60,60,0.3)',
      borderRadius: '8px',
      padding: '10px',
      color: '#ff6060',
      fontSize: '0.88rem',
      marginBottom: '20px',
    }
  };

  return (
    <div style={s.page}>
      <div style={s.box}>
        <div style={s.logo}>🔥</div>
        <h1 style={s.title}>BBRS Morphix IT</h1>
        <p style={s.sub}>Espace Administrateur</p>

        {error && <div style={s.error}>⚠️ {error}</div>}

        <form onSubmit={handleSubmit}>
          <label style={s.label}>IDENTIFIANT</label>
          <input
            style={s.input}
            type="text"
            placeholder="admin"
            value={form.username}
            onChange={e => setForm({ ...form, username: e.target.value })}
            required
          />
          <label style={s.label}>MOT DE PASSE</label>
          <input
            style={s.input}
            type="password"
            placeholder="••••••••"
            value={form.password}
            onChange={e => setForm({ ...form, password: e.target.value })}
            required
          />
          <button style={s.btn} type="submit" disabled={loading}>
            {loading ? '⏳ Connexion...' : '🔐 Se connecter'}
          </button>
        </form>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════
//  ARTICLE FORM
// ══════════════════════════════════════════════════════════════
function ArticleForm({ token, onSaved, editArticle, onCancel }) {
  const [form, setForm] = useState({
    title: editArticle?.title || '',
    description: editArticle?.description || '',
    category: editArticle?.category || 'Général',
    content: editArticle?.content || '',
    published: editArticle?.published ?? true,
  });
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [dragOver, setDragOver] = useState(false);
  const fileRef = useRef();

  const categories = ['Général', 'Tutoriel', 'Actualités', 'Sécurité', 'Réseau', 'Développement', 'Hardware', 'Cloud'];

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const formData = new FormData();
    Object.entries(form).forEach(([k, v]) => formData.append(k, v));
    if (file) formData.append('file', file);

    try {
      const url = editArticle
        ? `${API_URL}/api/admin/articles/${editArticle.id}`
        : `${API_URL}/api/admin/articles`;
      const method = editArticle ? 'PUT' : 'POST';

      const res = await fetch(url, {
        method,
        headers: { Authorization: `Bearer ${token}` },
        body: formData,
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      onSaved(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setDragOver(false);
    const f = e.dataTransfer.files[0];
    if (f) setFile(f);
  };

  const s = {
    form: { background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(0,200,0,0.15)', borderRadius: '16px', padding: '30px' },
    title: { color: '#ffd700', fontSize: '1.2rem', fontWeight: 700, marginBottom: '24px' },
    row: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' },
    group: { marginBottom: '16px' },
    label: { display: 'block', color: '#888', fontSize: '0.78rem', marginBottom: '6px', fontWeight: 600, letterSpacing: '0.5px' },
    input: {
      width: '100%', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(0,200,0,0.2)',
      borderRadius: '10px', padding: '11px 14px', color: '#e8e8e8', fontSize: '0.95rem',
      outline: 'none', boxSizing: 'border-box'
    },
    textarea: {
      width: '100%', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(0,200,0,0.2)',
      borderRadius: '10px', padding: '11px 14px', color: '#e8e8e8', fontSize: '0.95rem',
      outline: 'none', boxSizing: 'border-box', resize: 'vertical', minHeight: '100px'
    },
    select: {
      width: '100%', background: '#111', border: '1px solid rgba(0,200,0,0.2)',
      borderRadius: '10px', padding: '11px 14px', color: '#e8e8e8', fontSize: '0.95rem', outline: 'none'
    },
    dropZone: {
      border: `2px dashed ${dragOver ? '#00cc00' : 'rgba(0,200,0,0.25)'}`,
      borderRadius: '12px', padding: '30px', textAlign: 'center', cursor: 'pointer',
      background: dragOver ? 'rgba(0,200,0,0.05)' : 'transparent', transition: 'all 0.2s',
      marginBottom: '16px'
    },
    actions: { display: 'flex', gap: '12px', justifyContent: 'flex-end', marginTop: '8px' },
    btnPrimary: {
      background: loading ? '#444' : 'linear-gradient(135deg, #00cc00, #007700)',
      color: '#fff', border: 'none', borderRadius: '10px', padding: '12px 28px',
      fontWeight: 700, cursor: loading ? 'not-allowed' : 'pointer', fontSize: '0.95rem'
    },
    btnSecondary: {
      background: 'rgba(255,255,255,0.05)', color: '#aaa', border: '1px solid rgba(255,255,255,0.1)',
      borderRadius: '10px', padding: '12px 20px', cursor: 'pointer', fontSize: '0.95rem'
    },
    error: { background: 'rgba(255,60,60,0.1)', border: '1px solid rgba(255,60,60,0.3)', borderRadius: '8px', padding: '10px', color: '#ff6060', fontSize: '0.88rem', marginBottom: '16px' },
    toggle: { display: 'flex', alignItems: 'center', gap: '10px' }
  };

  return (
    <div style={s.form}>
      <h3 style={s.title}>{editArticle ? '✏️ Modifier l\'article' : '➕ Nouvel article'}</h3>
      {error && <div style={s.error}>⚠️ {error}</div>}
      <form onSubmit={handleSubmit}>
        <div style={s.group}>
          <label style={s.label}>TITRE *</label>
          <input style={s.input} value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="Titre de l'article" required />
        </div>
        <div style={s.row}>
          <div style={s.group}>
            <label style={s.label}>CATÉGORIE</label>
            <select style={s.select} value={form.category} onChange={e => setForm({ ...form, category: e.target.value })}>
              {categories.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div style={s.group}>
            <label style={s.label}>STATUT</label>
            <div style={{ ...s.input, display: 'flex', alignItems: 'center', gap: '10px' }}>
              <input type="checkbox" checked={form.published} onChange={e => setForm({ ...form, published: e.target.checked })} id="pub" style={{ width: 'auto' }} />
              <label htmlFor="pub" style={{ color: form.published ? '#00cc00' : '#888', cursor: 'pointer', margin: 0 }}>
                {form.published ? '✅ Publié' : '⏸️ Brouillon'}
              </label>
            </div>
          </div>
        </div>
        <div style={s.group}>
          <label style={s.label}>DESCRIPTION</label>
          <textarea style={s.textarea} value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} placeholder="Courte description visible sur la carte..." />
        </div>
        <div style={s.group}>
          <label style={s.label}>CONTENU</label>
          <textarea style={{ ...s.textarea, minHeight: '140px' }} value={form.content} onChange={e => setForm({ ...form, content: e.target.value })} placeholder="Contenu complet de l'article..." />
        </div>
        <div style={s.group}>
          <label style={s.label}>FICHIER JOINT (PDF, Image, Word, etc.)</label>
          <div
            style={s.dropZone}
            onDragOver={e => { e.preventDefault(); setDragOver(true); }}
            onDragLeave={() => setDragOver(false)}
            onDrop={handleDrop}
            onClick={() => fileRef.current.click()}
          >
            {file ? (
              <div>
                <div style={{ fontSize: '1.5rem', marginBottom: '6px' }}>📎</div>
                <div style={{ color: '#ffd700', fontWeight: 600 }}>{file.name}</div>
                <div style={{ color: '#555', fontSize: '0.8rem' }}>{(file.size / 1024).toFixed(1)} KB</div>
              </div>
            ) : editArticle?.file ? (
              <div>
                <div style={{ fontSize: '1.5rem', marginBottom: '6px' }}>📎</div>
                <div style={{ color: '#aaa' }}>Fichier actuel: <span style={{ color: '#ffd700' }}>{editArticle.file.originalname}</span></div>
                <div style={{ color: '#555', fontSize: '0.8rem', marginTop: '4px' }}>Glissez un nouveau fichier pour remplacer</div>
              </div>
            ) : (
              <div>
                <div style={{ fontSize: '2rem', marginBottom: '8px' }}>☁️</div>
                <div style={{ color: '#aaa' }}>Glissez votre fichier ici ou <span style={{ color: '#00cc00' }}>cliquez</span></div>
                <div style={{ color: '#555', fontSize: '0.8rem', marginTop: '4px' }}>PDF · Images · Word · Texte · Max 20MB</div>
              </div>
            )}
          </div>
          <input ref={fileRef} type="file" style={{ display: 'none' }} accept=".pdf,.jpg,.jpeg,.png,.gif,.webp,.docx,.doc,.md,.txt" onChange={e => setFile(e.target.files[0])} />
        </div>
        <div style={s.actions}>
          {onCancel && <button type="button" style={s.btnSecondary} onClick={onCancel}>Annuler</button>}
          <button type="submit" style={s.btnPrimary} disabled={loading}>
            {loading ? '⏳ Enregistrement...' : editArticle ? '💾 Mettre à jour' : '🚀 Publier'}
          </button>
        </div>
      </form>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════
//  DASHBOARD
// ══════════════════════════════════════════════════════════════
function Dashboard({ token, user, onLogout }) {
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState('list'); // list | new | edit
  const [editArticle, setEditArticle] = useState(null);
  const [deleteConfirm, setDeleteConfirm] = useState(null);

  useEffect(() => { fetchArticles(); }, []);

  const fetchArticles = async () => {
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/admin/articles`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      setArticles(data);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const handleDelete = async (id) => {
    try {
      await fetch(`${API_URL}/api/admin/articles/${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });
      setArticles(prev => prev.filter(a => a.id !== id));
      setDeleteConfirm(null);
    } catch (err) { console.error(err); }
  };

  const handleSaved = (article) => {
    if (editArticle) {
      setArticles(prev => prev.map(a => a.id === article.id ? article : a));
    } else {
      setArticles(prev => [article, ...prev]);
    }
    setView('list');
    setEditArticle(null);
  };

  const s = {
    page: { minHeight: '100vh', background: '#0a0f0a', fontFamily: "'Segoe UI', sans-serif", color: '#e8e8e8' },
    header: {
      background: 'rgba(0,0,0,0.5)',
      borderBottom: '1px solid rgba(0,200,0,0.15)',
      padding: '16px 30px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      position: 'sticky', top: 0, zIndex: 100,
    },
    headerLeft: { display: 'flex', alignItems: 'center', gap: '12px' },
    headerTitle: { color: '#ffd700', fontWeight: 800, fontSize: '1.1rem', margin: 0 },
    headerSub: { color: '#555', fontSize: '0.8rem' },
    headerRight: { display: 'flex', alignItems: 'center', gap: '12px' },
    userBadge: { background: 'rgba(0,200,0,0.1)', border: '1px solid rgba(0,200,0,0.2)', borderRadius: '20px', padding: '6px 14px', color: '#00cc00', fontSize: '0.85rem' },
    logoutBtn: { background: 'rgba(255,60,60,0.1)', border: '1px solid rgba(255,60,60,0.2)', borderRadius: '8px', padding: '8px 14px', color: '#ff6060', cursor: 'pointer', fontSize: '0.85rem' },
    main: { maxWidth: '1100px', margin: '0 auto', padding: '30px 20px' },
    topBar: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' },
    pageTitle: { color: '#ffd700', fontSize: '1.4rem', fontWeight: 700, margin: 0 },
    newBtn: { background: 'linear-gradient(135deg, #00cc00, #007700)', color: '#fff', border: 'none', borderRadius: '10px', padding: '10px 20px', cursor: 'pointer', fontWeight: 700, fontSize: '0.9rem' },
    stats: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '16px', marginBottom: '30px' },
    stat: { background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(0,200,0,0.1)', borderRadius: '12px', padding: '20px', textAlign: 'center' },
    statNum: { fontSize: '2rem', fontWeight: 800, color: '#ffd700' },
    statLabel: { color: '#555', fontSize: '0.85rem', marginTop: '4px' },
    table: { width: '100%', borderCollapse: 'collapse' },
    th: { color: '#555', fontSize: '0.75rem', fontWeight: 600, letterSpacing: '0.5px', padding: '8px 12px', textAlign: 'left', borderBottom: '1px solid rgba(255,255,255,0.05)' },
    td: { padding: '14px 12px', borderBottom: '1px solid rgba(255,255,255,0.04)', verticalAlign: 'middle' },
    badge: (pub) => ({
      display: 'inline-block',
      background: pub ? 'rgba(0,200,0,0.15)' : 'rgba(255,200,0,0.1)',
      color: pub ? '#00cc00' : '#ffcc00',
      borderRadius: '20px',
      padding: '3px 10px',
      fontSize: '0.75rem',
      fontWeight: 600
    }),
    editBtn: { background: 'rgba(255,215,0,0.1)', color: '#ffd700', border: '1px solid rgba(255,215,0,0.2)', borderRadius: '7px', padding: '5px 12px', cursor: 'pointer', fontSize: '0.8rem', marginRight: '6px' },
    delBtn: { background: 'rgba(255,60,60,0.1)', color: '#ff6060', border: '1px solid rgba(255,60,60,0.2)', borderRadius: '7px', padding: '5px 12px', cursor: 'pointer', fontSize: '0.8rem' },
    confirmOverlay: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.8)', zIndex: 200, display: 'flex', alignItems: 'center', justifyContent: 'center' },
    confirmBox: { background: '#111', border: '1px solid rgba(255,60,60,0.3)', borderRadius: '16px', padding: '30px', maxWidth: '360px', textAlign: 'center' }
  };

  const published = articles.filter(a => a.published).length;
  const drafts = articles.filter(a => !a.published).length;

  return (
    <div style={s.page}>
      {/* Header */}
      <div style={s.header}>
        <div style={s.headerLeft}>
          <span style={{ fontSize: '1.5rem' }}>🔥</span>
          <div>
            <div style={s.headerTitle}>BBRS Morphix IT</div>
            <div style={s.headerSub}>Tableau de bord</div>
          </div>
        </div>
        <div style={s.headerRight}>
          <span style={s.userBadge}>👤 {user.username}</span>
          <button style={s.logoutBtn} onClick={onLogout}>Déconnexion</button>
        </div>
      </div>

      <div style={s.main}>
        {view === 'new' || view === 'edit' ? (
          <ArticleForm
            token={token}
            editArticle={editArticle}
            onSaved={handleSaved}
            onCancel={() => { setView('list'); setEditArticle(null); }}
          />
        ) : (
          <>
            <div style={s.topBar}>
              <h2 style={s.pageTitle}>📝 Mes articles</h2>
              <button style={s.newBtn} onClick={() => setView('new')}>+ Nouvel article</button>
            </div>

            {/* Stats */}
            <div style={s.stats}>
              <div style={s.stat}><div style={s.statNum}>{articles.length}</div><div style={s.statLabel}>Total articles</div></div>
              <div style={s.stat}><div style={{ ...s.statNum, color: '#00cc00' }}>{published}</div><div style={s.statLabel}>Publiés</div></div>
              <div style={s.stat}><div style={{ ...s.statNum, color: '#ffcc00' }}>{drafts}</div><div style={s.statLabel}>Brouillons</div></div>
            </div>

            {/* Table */}
            {loading ? (
              <div style={{ textAlign: 'center', padding: '60px', color: '#555' }}>⏳ Chargement...</div>
            ) : articles.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '60px', color: '#555' }}>
                <div style={{ fontSize: '3rem', marginBottom: '12px' }}>📭</div>
                <p>Aucun article. Créez le premier !</p>
              </div>
            ) : (
              <div style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(0,200,0,0.1)', borderRadius: '14px', overflow: 'hidden' }}>
                <table style={s.table}>
                  <thead>
                    <tr>
                      <th style={s.th}>TITRE</th>
                      <th style={s.th}>CATÉGORIE</th>
                      <th style={s.th}>STATUT</th>
                      <th style={s.th}>FICHIER</th>
                      <th style={s.th}>DATE</th>
                      <th style={s.th}>ACTIONS</th>
                    </tr>
                  </thead>
                  <tbody>
                    {articles.map(article => (
                      <tr key={article.id}>
                        <td style={{ ...s.td, color: '#e8e8e8', fontWeight: 600, maxWidth: '220px' }}>
                          {article.title.length > 40 ? article.title.slice(0, 40) + '...' : article.title}
                        </td>
                        <td style={{ ...s.td, color: '#888' }}>{article.category}</td>
                        <td style={s.td}><span style={s.badge(article.published)}>{article.published ? '✅ Publié' : '⏸️ Brouillon'}</span></td>
                        <td style={{ ...s.td, color: '#666' }}>
                          {article.file ? <span title={article.file.originalname}>📎 Oui</span> : '—'}
                        </td>
                        <td style={{ ...s.td, color: '#666', fontSize: '0.85rem' }}>{formatDate(article.createdAt)}</td>
                        <td style={s.td}>
                          <button style={s.editBtn} onClick={() => { setEditArticle(article); setView('edit'); }}>✏️ Éditer</button>
                          <button style={s.delBtn} onClick={() => setDeleteConfirm(article.id)}>🗑️</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </>
        )}
      </div>

      {/* Confirm delete */}
      {deleteConfirm && (
        <div style={s.confirmOverlay}>
          <div style={s.confirmBox}>
            <div style={{ fontSize: '2.5rem', marginBottom: '12px' }}>🗑️</div>
            <h3 style={{ color: '#ff6060', marginBottom: '8px' }}>Supprimer l'article ?</h3>
            <p style={{ color: '#888', fontSize: '0.9rem', marginBottom: '24px' }}>Cette action est irréversible.</p>
            <div style={{ display: 'flex', gap: '12px', justifyContent: 'center' }}>
              <button style={{ ...s.editBtn, padding: '10px 20px' }} onClick={() => setDeleteConfirm(null)}>Annuler</button>
              <button style={{ ...s.delBtn, padding: '10px 20px' }} onClick={() => handleDelete(deleteConfirm)}>Supprimer</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════
//  MAIN EXPORT
// ══════════════════════════════════════════════════════════════
export default function Admin() {
  const [token, setToken] = useState(() => localStorage.getItem('bbrs_token'));
  const [user, setUser] = useState(null);
  const [checking, setChecking] = useState(true);

  useEffect(() => {
    if (token) {
      fetch(`${API_URL}/api/auth/me`, { headers: { Authorization: `Bearer ${token}` } })
        .then(r => r.json())
        .then(data => { if (data.user) setUser(data.user); else handleLogout(); })
        .catch(handleLogout)
        .finally(() => setChecking(false));
    } else {
      setChecking(false);
    }
  }, []);

  const handleLogin = (t, u) => { setToken(t); setUser(u); };
  const handleLogout = () => {
    localStorage.removeItem('bbrs_token');
    setToken(null);
    setUser(null);
  };

  if (checking) return (
    <div style={{ minHeight: '100vh', background: '#0a0f0a', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#ffd700', fontSize: '1.5rem' }}>
      🔥 Chargement...
    </div>
  );

  if (!token || !user) return <LoginForm onLogin={handleLogin} />;
  return <Dashboard token={token} user={user} onLogout={handleLogout} />;
}
